#include <initializer_list>
#include <iostream>

class IntArray {
    int m_size{};
    int* m_data{};
public:
    IntArray(std::initializer_list<int> list)
        : m_size{ static_cast<int>(list.size()) }
        , m_data{ new int[list.size()] } {
        int i{ 0 };
        for (int v : list)
            m_data[i++] = v;
    }
    IntArray& operator=(std::initializer_list<int> list) {
        delete[] m_data;
        m_size = static_cast<int>(list.size());
        m_data = new int[list.size()];
        int i{ 0 };
        for (int v : list)
            m_data[i++] = v;
        return *this;
    }
    ~IntArray() { delete[] m_data; }
    int size() const { return m_size; }
    int operator[](int index) const { return m_data[index]; }
};

void printElements(const IntArray& arr) {
    for (int i{ 0 }; i < arr.size(); ++i) {
        if (i > 0) std::cout << ' ';
        std::cout << arr[i];
    }
}

int main() {
    IntArray arr{ 1, 2, 3 };
    std::cout << "before: ";
    printElements(arr);
    std::cout << '\n';
    int x{};
    std::cin >> x;
    arr = { x, x * 2, x * 3, x * 4 };
    std::cout << "after: ";
    printElements(arr);
    std::cout << '\n';
    int sum{ 0 };
    for (int i{ 0 }; i < arr.size(); ++i)
        sum += arr[i];
    std::cout << "sum: " << sum << '\n';
    return 0;
}
